  "design_rules": {
    "unit_storage_rule": "同维度所有属性统一按 measurement_dimension.base_unit_id 指定的单位存储，attribute_def 不再冗余存储单位字段",
    "unit_conversion": "unit_of_measure.to_base_factor 用于将任意单位换算到基准单位。例如 inch->mm 系数为 25.4",
    "unit_scope_config": "attribute_unit_scope_config 控制运营录入时可用单位（类目/品牌/系列维度），不涉及前端展示。前端展示单位由 country_display_unit 控制",
    "country_display_unit": "前端展示单位配置：country_display_unit 表通过 category_id 可空实现兜底逻辑。category_id 为空=国家×维度默认，不为空=类目级覆盖。查询时先查类目级（country+dimension+category），没有则查国家级默认（country+dimension+category=null）。本期 country_code 写死 US",
    "attribute_value_split": "spu_attribute_value 和 standard_sku_attribute 的属性值按类型分存：text_value（文本）、numeric_value（数值，按基准单位存储）、option_id（枚举选项）",
    "three_layer_model": "标品层（厂商定义不可改）→ 二手商品层（一物一码独立状态）→ 渠道层（多渠道分发独立控价）",
    "value_level_rule": "attribute_scope_config.value_level 控制属性值存储层级（SPU/SKU/ITEM）。约束：key 属性→必须 SPU，sale 属性→必须 SKU，non_key 属性→灵活（SPU/SKU/ITEM 均可）。value_level=ITEM 的属性值存储在 used_item_attribute_value 表"
  }
}
